module flash_memory (
    input wire clk,
    input wire write_enable,
    input wire [4:0] data_in,
    output reg [4:0] data_out
);
  wire _tap_clk = clk & {1{1'b1}};


    always @(posedge clk) begin
        if (write_enable) begin
            data_out <= data_in;
        end
    end
endmodule
